/**
 * Apotheca Marketing Suite — Visual Email Editor + Campaign Manager
 * Drag-and-drop email editor with template library.
 * Uses wp-element (React) for campaign list/create, jQuery + HTML5 DnD for the editor canvas.
 */
(function ($) {
    'use strict';

    var el = wp.element.createElement;
    var useState = wp.element.useState;
    var useEffect = wp.element.useEffect;
    var Fragment = wp.element.Fragment;
    var Button = wp.components.Button;
    var TextControl = wp.components.TextControl;
    var SelectControl = wp.components.SelectControl;
    var Notice = wp.components.Notice;
    var Spinner = wp.components.Spinner;
    var apiFetch = wp.apiFetch;
    var cfg = window.amsEmailEditor || {};

    var FONT_STACK = "'Montserrat','Century Gothic','Trebuchet MS',Arial,Helvetica,sans-serif";
    var FONT_IMPORT = "@import url('https://fonts.googleapis.com/css2?family=Montserrat:ital,wght@0,300;0,400;0,500;0,600;0,700;0,800;1,400;1,700&display=swap');";

    /* ── Block type definitions ── */
    var BLOCK_DEFS = {
        text:       { label: 'Text', icon: 'dashicons-editor-textcolor', defaults: { content: '<p>Enter your text here...</p>', align: 'left', padding: '10px 20px' } },
        image:      { label: 'Image', icon: 'dashicons-format-image', defaults: { src: '', alt: '', width: '100%', align: 'center', link: '', padding: '10px 20px' } },
        button:     { label: 'Button', icon: 'dashicons-button', defaults: { text: 'Click Here', url: '#', bgColor: '#2271b1', textColor: '#ffffff', borderRadius: '4px', align: 'center', padding: '12px 24px', containerPadding: '10px 20px' } },
        divider:    { label: 'Divider', icon: 'dashicons-minus', defaults: { color: '#cccccc', thickness: '1px', style: 'solid', padding: '10px 20px' } },
        spacer:     { label: 'Spacer', icon: 'dashicons-image-flip-vertical', defaults: { height: '20px' } },
        'product-card': { label: 'Product Card', icon: 'dashicons-cart', defaults: { productName: '{{product_name}}', productUrl: '{{product_url}}', imageUrl: '{{product_image_url}}', price: '{{product_price}}', buttonText: 'Shop Now', buttonColor: '#2271b1', padding: '10px 20px' } },
        reviews:    { label: 'Reviews', icon: 'dashicons-star-filled', defaults: { mode: 'review_request', heading: 'How was your purchase?', buttonText: 'Leave a Review', buttonColor: '#2271b1', padding: '10px 20px' } },
        'social-links': { label: 'Social Links', icon: 'dashicons-share', defaults: { facebook: '#', instagram: '#', twitter: '#', youtube: '', align: 'center', padding: '10px 20px' } },
        'unsubscribe-footer': { label: 'Unsub Footer', icon: 'dashicons-dismiss', defaults: { text: 'You received this email because you opted in at {{shop_name}}.', linkText: 'Unsubscribe', align: 'center', padding: '20px' } },
        'blank-row': { label: 'Blank Row', icon: 'dashicons-minus', defaults: { width: '100%', height: '40px', bgColor: '#f7f7f7' } }
    };

    /* ── Pre-built Email Templates ── */
    var EMAIL_TEMPLATES = {
        blank: { name: 'Blank', desc: 'Start from scratch', rows: [] },
        welcome: {
            name: 'Welcome Email', desc: 'Greet new subscribers',
            rows: [
                { blocks: [{ type: 'image', props: { src: '', alt: 'Logo', width: '200px', align: 'center', padding: '20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<h1 style="text-align:center;margin:0;">Welcome to {{shop_name}}!</h1>', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<p style="text-align:center;font-size:16px;color:#555;">Thanks for joining us! We\'re excited to have you as part of our community.</p><ul style="color:#555;"><li>Exclusive deals & early access</li><li>Expert tips & product guides</li><li>New arrival alerts</li></ul>', align: 'left', padding: '10px 20px' } }] },
                { blocks: [{ type: 'button', props: { text: 'Start Shopping', url: '{{shop_url}}', bgColor: '#2271b1', textColor: '#ffffff', borderRadius: '4px', align: 'center', padding: '14px 32px', containerPadding: '10px 20px' } }] },
                { blocks: [{ type: 'spacer', props: { height: '20px' } }] },
                { blocks: [{ type: 'social-links', props: { facebook: '#', instagram: '#', twitter: '#', youtube: '', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'unsubscribe-footer', props: { text: 'You received this email because you signed up at {{shop_name}}.', linkText: 'Unsubscribe', align: 'center', padding: '20px' } }] }
            ]
        },
        abandoned_cart: {
            name: 'Abandoned Cart', desc: 'Recover lost sales',
            rows: [
                { blocks: [{ type: 'text', props: { content: '<h1 style="text-align:center;margin:0;">You left something behind!</h1>', align: 'center', padding: '20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<p style="text-align:center;font-size:16px;color:#555;">It looks like you forgot to complete your purchase. Don\'t worry — your items are still waiting for you.</p>', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'product-card', props: { productName: '{{product_name}}', productUrl: '{{product_url}}', imageUrl: '{{product_image_url}}', price: '{{product_price}}', buttonText: 'View Product', buttonColor: '#2271b1', padding: '10px 20px' } }] },
                { blocks: [{ type: 'button', props: { text: 'Complete Your Order', url: '{{cart_url}}', bgColor: '#d63638', textColor: '#ffffff', borderRadius: '4px', align: 'center', padding: '14px 32px', containerPadding: '10px 20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<p style="text-align:center;font-size:13px;color:#999;">Need help? Just reply to this email.</p>', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'unsubscribe-footer', props: { text: 'You received this because you have an account at {{shop_name}}.', linkText: 'Unsubscribe', align: 'center', padding: '20px' } }] }
            ]
        },
        order_confirmation: {
            name: 'Order Confirmation', desc: 'Confirm order details',
            rows: [
                { blocks: [{ type: 'text', props: { content: '<h1 style="text-align:center;margin:0;">Order Confirmed! \u2705</h1>', align: 'center', padding: '20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<p style="text-align:center;font-size:16px;color:#555;">Thank you for your order, {{customer_first_name}}!</p>', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'divider', props: { color: '#e0e0e0', thickness: '1px', style: 'solid', padding: '10px 20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<table width="100%" style="font-size:14px;"><tr><td><strong>Order:</strong></td><td style="text-align:right;">{{order_number}}</td></tr><tr><td><strong>Date:</strong></td><td style="text-align:right;">{{order_date}}</td></tr><tr><td><strong>Total:</strong></td><td style="text-align:right;font-weight:bold;font-size:18px;">{{order_total}}</td></tr></table>', align: 'left', padding: '10px 20px' } }] },
                { blocks: [{ type: 'divider', props: { color: '#e0e0e0', thickness: '1px', style: 'solid', padding: '10px 20px' } }] },
                { blocks: [{ type: 'product-card', props: { productName: '{{product_name}}', productUrl: '{{product_url}}', imageUrl: '{{product_image_url}}', price: '{{product_price}}', buttonText: 'View Product', buttonColor: '#2271b1', padding: '10px 20px' } }] },
                { blocks: [{ type: 'button', props: { text: 'Track Your Order', url: '{{order_url}}', bgColor: '#2271b1', textColor: '#ffffff', borderRadius: '4px', align: 'center', padding: '14px 32px', containerPadding: '10px 20px' } }] },
                { blocks: [{ type: 'unsubscribe-footer', props: { text: 'You received this because you placed an order at {{shop_name}}.', linkText: 'Unsubscribe', align: 'center', padding: '20px' } }] }
            ]
        },
        review_request: {
            name: 'Review Request', desc: 'Ask for product reviews',
            rows: [
                { blocks: [{ type: 'text', props: { content: '<h1 style="text-align:center;margin:0;">How did we do?</h1>', align: 'center', padding: '20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<p style="text-align:center;font-size:16px;color:#555;">Hi {{customer_first_name}}, we hope you\'re loving your recent purchase! Your feedback helps us improve.</p>', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'product-card', props: { productName: '{{product_name}}', productUrl: '{{product_url}}', imageUrl: '{{product_image_url}}', price: '{{product_price}}', buttonText: 'View Product', buttonColor: '#2271b1', padding: '10px 20px' } }] },
                { blocks: [{ type: 'reviews', props: { mode: 'review_gate', heading: 'Rate your experience', buttonText: 'Leave a Review', buttonColor: '#f5a623', padding: '10px 20px' } }] },
                { blocks: [{ type: 'unsubscribe-footer', props: { text: 'You received this because you purchased from {{shop_name}}.', linkText: 'Unsubscribe', align: 'center', padding: '20px' } }] }
            ]
        },
        newsletter: {
            name: 'Newsletter', desc: 'Regular newsletter layout',
            rows: [
                { blocks: [{ type: 'image', props: { src: '', alt: 'Logo', width: '180px', align: 'center', padding: '20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<h1 style="text-align:center;margin:0;">Monthly Newsletter</h1><p style="text-align:center;color:#999;font-size:13px;margin:4px 0 0;">{{current_month}} Edition</p>', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'divider', props: { color: '#2271b1', thickness: '2px', style: 'solid', padding: '10px 20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<h2 style="margin:0 0 8px;">What\'s New</h2><p style="color:#555;">Share your latest updates and stories here.</p>', align: 'left', padding: '10px 20px' } }] },
                { blocks: [{ type: 'image', props: { src: '', alt: 'Featured', width: '100%', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'button', props: { text: 'Read More', url: '#', bgColor: '#2271b1', textColor: '#ffffff', borderRadius: '4px', align: 'center', padding: '12px 28px', containerPadding: '10px 20px' } }] },
                { blocks: [{ type: 'divider', props: { color: '#e0e0e0', thickness: '1px', style: 'solid', padding: '10px 20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<h2 style="margin:0 0 8px;">Featured Products</h2>', align: 'left', padding: '10px 20px' } }] },
                { blocks: [{ type: 'product-card', props: { productName: '{{product_name}}', productUrl: '{{product_url}}', imageUrl: '{{product_image_url}}', price: '{{product_price}}', buttonText: 'Shop Now', buttonColor: '#2271b1', padding: '10px 20px' } }] },
                { blocks: [{ type: 'social-links', props: { facebook: '#', instagram: '#', twitter: '#', youtube: '', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'unsubscribe-footer', props: { text: 'You received this newsletter because you subscribed at {{shop_name}}.', linkText: 'Unsubscribe', align: 'center', padding: '20px' } }] }
            ]
        },
        promo_sale: {
            name: 'Promo / Sale', desc: 'Announce sales & discounts',
            rows: [
                { blocks: [{ type: 'text', props: { content: '<h1 style="text-align:center;margin:0;font-size:28px;color:#d63638;">\ud83d\udd25 SALE \u2014 Up to 50% OFF!</h1>', align: 'center', padding: '20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<p style="text-align:center;font-size:18px;color:#555;margin:0;">For a limited time only. Don\'t miss out!</p>', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'image', props: { src: '', alt: 'Sale banner', width: '100%', align: 'center', link: '#', padding: '10px 20px' } }] },
                { blocks: [{ type: 'product-card', props: { productName: '{{product_name}}', productUrl: '{{product_url}}', imageUrl: '{{product_image_url}}', price: '{{product_price}}', buttonText: 'Shop Now', buttonColor: '#d63638', padding: '10px 20px' } }] },
                { blocks: [{ type: 'text', props: { content: '<div style="text-align:center;background:#fef3f3;border:2px dashed #d63638;border-radius:8px;padding:16px;"><p style="margin:0 0 4px;font-size:13px;color:#999;text-transform:uppercase;">Use code</p><p style="margin:0;font-size:28px;font-weight:700;color:#d63638;letter-spacing:2px;">SAVE50</p></div>', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'button', props: { text: 'Shop the Sale', url: '{{shop_url}}', bgColor: '#d63638', textColor: '#ffffff', borderRadius: '4px', align: 'center', padding: '16px 40px', containerPadding: '10px 20px' } }] },
                { blocks: [{ type: 'social-links', props: { facebook: '#', instagram: '#', twitter: '#', youtube: '', align: 'center', padding: '10px 20px' } }] },
                { blocks: [{ type: 'unsubscribe-footer', props: { text: 'You received this because you opted in at {{shop_name}}.', linkText: 'Unsubscribe', align: 'center', padding: '20px' } }] }
            ]
        }
    };

    /* ── jQuery-based Email Editor (modeled on working e-commerce builder) ── */
    var Editor = {
        el: null,
        campaignId: 0,
        structure: null,
        selectedRow: null,
        _dragging: false,

        init: function (node) {
            this.el = $(node);
            this.campaignId = parseInt(this.el.data('campaign-id')) || 0;
            this.structure = { settings: this.getDefaultSettings(), rows: [] };
            this.load();
        },

        getDefaultSettings: function () {
            return {
                bgColor: '#f4f4f4', contentBg: '#ffffff', fontWeight: '400',
                fontSize: '16px', textColor: '#333333', linkColor: '#2271b1',
                maxWidth: '600', preheader: ''
            };
        },

        load: function () {
            var self = this;
            if (!this.campaignId) {
                this.showTemplateChooser();
                return;
            }
            this.el.html('<div style="padding:40px;text-align:center;">Loading...</div>');
            apiFetch({
                path: '/ams/v1/admin/campaigns/' + this.campaignId,
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(function (c) {
                if (c._blocks_json) {
                    try {
                        var parsed = JSON.parse(c._blocks_json);
                        if (parsed.rows && parsed.rows.length > 0) {
                            self.structure.rows = parsed.rows;
                            if (parsed.settings) self.structure.settings = $.extend({}, self.getDefaultSettings(), parsed.settings);
                        } else if (parsed.blocks && parsed.blocks.length > 0) {
                            /* Migrate old flat blocks format to rows format */
                            self.structure.rows = parsed.blocks.map(function (b) {
                                return { blocks: [{ type: b.type, props: b }] };
                            });
                            if (parsed.settings) self.structure.settings = $.extend({}, self.getDefaultSettings(), parsed.settings);
                        } else {
                            self.showTemplateChooser();
                            return;
                        }
                    } catch (e) {
                        self.showTemplateChooser();
                        return;
                    }
                } else {
                    self.showTemplateChooser();
                    return;
                }
                self.render();
                self.bindEvents();
            }).catch(function () {
                self.showTemplateChooser();
            });
        },

        /* ── Template Chooser (shows built-in + saved templates) ── */
        showTemplateChooser: function () {
            var self = this;
            this.el.html('<div style="padding:40px;text-align:center;">Loading templates...</div>');

            /* Fetch saved templates from the database */
            apiFetch({
                path: '/ams/v1/admin/email-templates',
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(function (savedTemplates) {
                self._renderTemplateChooser(savedTemplates || []);
            }).catch(function () {
                self._renderTemplateChooser([]);
            });
        },

        _renderTemplateChooser: function (savedTemplates) {
            var self = this;
            var html = '<div class="ams-template-overlay">';
            html += '<div class="ams-template-modal">';
            html += '<div class="ams-template-modal-header"><h2>Choose a Template</h2>';
            html += '<button class="button ams-tpl-skip">Start Blank</button></div>';
            html += '<div class="ams-template-modal-body">';

            /* Saved templates section */
            if (savedTemplates.length > 0) {
                html += '<h3 style="margin:0 0 12px;font-size:14px;color:#1e1e1e;">Your Saved Templates</h3>';
                html += '<div class="ams-template-grid" style="margin-bottom:24px;">';
                for (var i = 0; i < savedTemplates.length; i++) {
                    var st = savedTemplates[i];
                    html += '<div class="ams-template-card" data-saved-id="' + st.id + '">';
                    html += '<div class="ams-template-card-preview"><div class="ams-template-card-preview-inner">';
                    html += '<div style="text-align:center;padding:30px;color:#2271b1;"><span class="dashicons dashicons-media-document" style="font-size:36px;width:36px;height:36px;"></span></div>';
                    html += '</div></div>';
                    html += '<div class="ams-template-card-info"><h4>' + self.esc(st.name) + '</h4><p>' + self.esc(st.description || 'Custom template') + '</p></div>';
                    html += '</div>';
                }
                html += '</div>';
            }

            /* Built-in templates */
            html += '<h3 style="margin:0 0 12px;font-size:14px;color:#1e1e1e;">Built-in Templates</h3>';
            html += '<div class="ams-template-grid">';
            for (var key in EMAIL_TEMPLATES) {
                var tpl = EMAIL_TEMPLATES[key];
                html += '<div class="ams-template-card" data-template="' + key + '">';
                html += '<div class="ams-template-card-preview"><div class="ams-template-card-preview-inner">';
                if (key === 'blank') {
                    html += '<div style="text-align:center;padding:40px;color:#999;">Empty canvas</div>';
                } else {
                    for (var r = 0; r < tpl.rows.length; r++) {
                        for (var b = 0; b < tpl.rows[r].blocks.length; b++) {
                            html += self.renderBlockPreview(tpl.rows[r].blocks[b]);
                        }
                    }
                }
                html += '</div></div>';
                html += '<div class="ams-template-card-info"><h4>' + tpl.name + '</h4><p>' + tpl.desc + '</p></div>';
                html += '</div>';
            }
            html += '</div></div></div></div>';
            this.el.html(html);

            /* Click handlers */
            this.el.on('click.tpl', '.ams-template-card[data-template]', function () {
                self.applyTemplate($(this).data('template'));
            });
            this.el.on('click.tpl', '.ams-template-card[data-saved-id]', function () {
                self.applySavedTemplate($(this).data('saved-id'));
            });
            this.el.on('click.tpl', '.ams-tpl-skip', function () {
                self.applyTemplate('blank');
            });
        },

        applyTemplate: function (key) {
            this.el.off('.tpl');
            var tpl = EMAIL_TEMPLATES[key];
            if (tpl && tpl.rows) {
                this.structure.rows = JSON.parse(JSON.stringify(tpl.rows));
            } else {
                this.structure.rows = [];
            }
            this.render();
            this.bindEvents();
        },

        applySavedTemplate: function (savedId) {
            var self = this;
            this.el.off('.tpl');
            this.el.html('<div style="padding:40px;text-align:center;">Loading template...</div>');
            apiFetch({
                path: '/ams/v1/admin/email-templates/' + savedId,
                headers: { 'X-WP-Nonce': cfg.nonce },
            }).then(function (t) {
                if (t.structure_json) {
                    try {
                        var parsed = JSON.parse(t.structure_json);
                        if (parsed.rows) self.structure.rows = JSON.parse(JSON.stringify(parsed.rows));
                        if (parsed.settings) self.structure.settings = $.extend({}, self.getDefaultSettings(), parsed.settings);
                    } catch (e) { /* ignore */ }
                }
                self.render();
                self.bindEvents();
            }).catch(function () {
                self.render();
                self.bindEvents();
            });
        },

        /* ── Render the full editor ── */
        render: function () {
            var self = this;
            var s = this.structure.settings;
            var html = '';

            /* Sidebar */
            html += '<div class="ams-etb-sidebar">';
            html += '<div class="ams-etb-tabs">';
            html += '<button class="ams-etb-tab active" data-panel="blocks">Blocks</button>';
            html += '<button class="ams-etb-tab" data-panel="settings">Design</button>';
            html += '<button class="ams-etb-tab" data-panel="block-settings">Block</button>';
            html += '</div>';

            /* Blocks panel */
            html += '<div class="ams-etb-panel active" data-panel="blocks">';
            html += '<div class="ams-etb-block-grid">';
            for (var type in BLOCK_DEFS) {
                var bd = BLOCK_DEFS[type];
                html += '<div class="ams-etb-block-item" data-type="' + type + '" draggable="true">';
                html += '<span class="dashicons ' + bd.icon + '"></span>';
                html += '<span>' + bd.label + '</span>';
                html += '</div>';
            }
            html += '</div>';
            html += '<div style="padding:12px;border-top:1px solid #e0e0e0;"><button class="button ams-etb-browse-templates" style="width:100%;">Browse Templates</button></div>';
            html += '</div>';

            /* Design settings panel */
            html += '<div class="ams-etb-panel" data-panel="settings">';
            html += this.renderDesignSettings();
            html += '</div>';

            /* Block settings panel */
            html += '<div class="ams-etb-panel" data-panel="block-settings">';
            html += '<p style="color:#999;text-align:center;padding:20px;">Select a block to edit its settings.</p>';
            html += '</div>';

            html += '</div>'; /* end sidebar */

            /* Canvas */
            html += '<div class="ams-etb-canvas">';

            /* Toolbar */
            html += '<div class="ams-etb-toolbar">';
            html += '<strong style="flex:1;">Email Editor</strong>';
            html += '<button class="button ams-etb-preview-btn">Preview</button>';
            html += '<button class="button button-primary ams-etb-save-btn">Save</button>';
            html += '</div>';

            /* Email frame */
            html += '<div class="ams-etb-email-frame" style="max-width:' + (parseInt(s.maxWidth) || 600) + 'px;">';
            html += '<div class="ams-etb-email-body" style="background:' + (s.contentBg || '#fff') + ';">';
            html += this.renderRows();
            html += '</div></div>';

            html += '</div>'; /* end canvas */

            this.el.html(html);
            this.initSortable();
        },

        /* ── Render all rows ── */
        renderRows: function () {
            if (!this.structure.rows || !this.structure.rows.length) {
                return '<div class="ams-etb-drop-zone">Drag blocks here to start building your email</div>';
            }
            var html = '<div class="ams-etb-drop-zone has-blocks">';
            for (var i = 0; i < this.structure.rows.length; i++) {
                html += this.renderRow(i, this.structure.rows[i]);
            }
            html += '</div>';
            return html;
        },

        /* ── Render single row ── */
        renderRow: function (index, row) {
            var blocks = row.blocks || [];
            var rowClass = 'ams-etb-row';
            var rowStyle = '';

            /* Blank row gets background color */
            if (blocks.length === 1 && blocks[0].type === 'blank-row') {
                var brBg = blocks[0].props.bgColor || '#f7f7f7';
                rowStyle = ' style="background:' + brBg + ';"';
            }

            var html = '<div class="' + rowClass + '" data-index="' + index + '"' + rowStyle + '>';
            html += '<div class="ams-etb-row-actions">';
            html += '<button class="ams-etb-row-action move" title="Drag to reorder"><span class="dashicons dashicons-move"></span></button>';
            html += '<button class="ams-etb-row-action duplicate" title="Duplicate"><span class="dashicons dashicons-admin-page"></span></button>';
            html += '<button class="ams-etb-row-action delete" title="Delete"><span class="dashicons dashicons-trash"></span></button>';
            html += '</div>';

            for (var j = 0; j < blocks.length; j++) {
                html += '<div class="ams-etb-block" data-row="' + index + '" data-block="' + j + '" data-type="' + blocks[j].type + '">';
                html += this.renderBlockPreview(blocks[j]);
                html += '</div>';
            }

            if (!blocks.length) {
                html += '<div style="padding:20px;text-align:center;color:#ccc;">Empty row</div>';
            }

            html += '</div>';
            return html;
        },

        /* ── Block preview HTML ── */
        renderBlockPreview: function (block) {
            var type = block.type;
            var p = block.props || {};
            var font = FONT_STACK;
            var pad = p.padding || '10px 20px';

            switch (type) {
                case 'text':
                    return '<div style="padding:' + pad + ';text-align:' + (p.align || 'left') + ';">' + (p.content || '<p>Text block</p>') + '</div>';
                case 'image':
                    if (p.src) {
                        return '<div style="padding:' + pad + ';text-align:' + (p.align || 'center') + ';"><img src="' + this.esc(p.src) + '" alt="' + this.esc(p.alt || '') + '" style="max-width:' + (p.width || '100%') + ';height:auto;" /></div>';
                    }
                    return '<div style="padding:20px;text-align:center;background:#f0f0f1;border:1px dashed #c3c4c7;border-radius:4px;margin:10px 20px;"><span class="dashicons dashicons-format-image" style="font-size:32px;color:#ccc;"></span><br><small style="color:#999;">Image placeholder</small></div>';
                case 'button':
                    return '<div style="padding:' + (p.containerPadding || '10px 20px') + ';text-align:' + (p.align || 'center') + ';"><span style="display:inline-block;background:' + (p.bgColor || '#2271b1') + ';color:' + (p.textColor || '#fff') + ';padding:' + (p.padding || '12px 24px') + ';border-radius:' + (p.borderRadius || '4px') + ';font-size:16px;font-weight:600;font-family:' + font + ';">' + this.esc(p.text || 'Button') + '</span></div>';
                case 'divider':
                    return '<div style="padding:' + pad + ';"><hr style="border:none;border-top:' + (p.thickness || '1px') + ' ' + (p.style || 'solid') + ' ' + (p.color || '#ccc') + ';margin:0;" /></div>';
                case 'spacer':
                    return '<div style="height:' + (p.height || '20px') + ';min-height:10px;background:repeating-linear-gradient(45deg,transparent,transparent 5px,#f8f8f8 5px,#f8f8f8 10px);"></div>';
                case 'product-card':
                    return '<table cellpadding="0" cellspacing="0" border="0" width="100%" style="font-family:' + font + ';"><tr>' +
                        '<td style="width:40%;padding:10px;"><img src="' + this.esc(p.imageUrl || '') + '" alt="' + this.esc(p.productName || '') + '" style="max-width:100%;height:auto;" /></td>' +
                        '<td style="width:60%;padding:10px;vertical-align:top;">' +
                        '<h3 style="margin:0 0 8px;font-family:' + font + ';">' + (p.productName || 'Product') + '</h3>' +
                        '<p style="margin:0 0 12px;font-size:18px;font-weight:600;">' + (p.price || '') + '</p>' +
                        '<span style="display:inline-block;background:' + (p.buttonColor || '#2271b1') + ';color:#fff;font-size:14px;font-weight:600;padding:10px 20px;border-radius:4px;">' + this.esc(p.buttonText || 'Shop Now') + '</span>' +
                        '</td></tr></table>';
                case 'reviews':
                    var rh = '<div style="text-align:center;padding:20px;background:#f9f9f9;border-radius:8px;">';
                    rh += '<h3 style="margin:0 0 12px;">' + (p.heading || 'Reviews') + '</h3>';
                    if (p.mode === 'review_request') {
                        rh += '<p style="color:#666;margin:0 0 16px;">We\u2019d love to hear about your purchase.</p>';
                        rh += '<span style="display:inline-block;background:' + (p.buttonColor || '#2271b1') + ';color:#fff;padding:12px 24px;border-radius:4px;font-weight:600;">' + this.esc(p.buttonText || 'Leave a Review') + '</span>';
                    } else if (p.mode === 'social_proof') {
                        rh += '<div style="background:#fff;border:1px solid #e0e0e0;border-radius:6px;padding:16px;text-align:left;">';
                        rh += '<div style="color:#f5a623;font-size:18px;">\u2605\u2605\u2605\u2605\u2605</div>';
                        rh += '<p style="margin:4px 0 0;font-style:italic;">"Amazing product!"</p></div>';
                    } else if (p.mode === 'review_gate') {
                        rh += '<p style="color:#666;margin:0 0 12px;">How would you rate your experience?</p>';
                        rh += '<div style="font-size:32px;letter-spacing:8px;">\u2605\u2605\u2605\u2605\u2605</div>';
                    }
                    rh += '</div>';
                    return rh;
                case 'social-links':
                    var sl = '<div style="text-align:' + (p.align || 'center') + ';padding:' + pad + ';">';
                    if (p.facebook) sl += '<span style="display:inline-block;margin:0 4px;padding:6px 10px;background:#e0e0e0;border-radius:4px;font-size:11px;">Facebook</span>';
                    if (p.instagram) sl += '<span style="display:inline-block;margin:0 4px;padding:6px 10px;background:#e0e0e0;border-radius:4px;font-size:11px;">Instagram</span>';
                    if (p.twitter) sl += '<span style="display:inline-block;margin:0 4px;padding:6px 10px;background:#e0e0e0;border-radius:4px;font-size:11px;">X</span>';
                    if (p.youtube) sl += '<span style="display:inline-block;margin:0 4px;padding:6px 10px;background:#e0e0e0;border-radius:4px;font-size:11px;">YouTube</span>';
                    sl += '</div>';
                    return sl;
                case 'unsubscribe-footer':
                    return '<div style="text-align:' + (p.align || 'center') + ';padding:' + (p.padding || '20px') + ';font-size:12px;color:#999;">' +
                        '<p style="margin:0 0 8px;">' + (p.text || '') + '</p>' +
                        '<a href="#" style="color:#2271b1;text-decoration:underline;">' + this.esc(p.linkText || 'Unsubscribe') + '</a></div>';
                case 'blank-row':
                    return '<div style="width:' + (p.width || '100%') + ';height:' + (p.height || '40px') + ';background:' + (p.bgColor || '#f7f7f7') + ';"></div>';
                default:
                    return '<div style="padding:10px 20px;color:#999;">Unknown: ' + type + '</div>';
            }
        },

        /* ── Design settings HTML ── */
        renderDesignSettings: function () {
            var s = this.structure.settings;
            var html = '<div class="ams-etb-settings-group"><h4>Colors</h4>';
            html += this.field('text', 'bgColor', 'Background', s.bgColor || '#f4f4f4');
            html += this.field('text', 'contentBg', 'Content BG', s.contentBg || '#ffffff');
            html += this.field('text', 'textColor', 'Text Color', s.textColor || '#333333');
            html += this.field('text', 'linkColor', 'Link Color', s.linkColor || '#2271b1');
            html += '</div>';
            html += '<div class="ams-etb-settings-group"><h4>Typography</h4>';
            html += '<div class="ams-etb-field"><label>Font</label><input type="text" value="Montserrat (brand)" disabled class="ams-etb-input" /></div>';
            html += this.field('select', 'fontWeight', 'Weight', s.fontWeight || '400', { '300': 'Light', '400': 'Regular', '500': 'Medium', '600': 'Semi-Bold', '700': 'Bold', '800': 'Extra Bold' });
            html += this.field('text', 'fontSize', 'Size', s.fontSize || '16px');
            html += '</div>';
            html += '<div class="ams-etb-settings-group"><h4>Layout</h4>';
            html += this.field('number', 'maxWidth', 'Width (px)', s.maxWidth || '600');
            html += '</div>';
            html += '<div class="ams-etb-settings-group"><h4>Preheader</h4>';
            html += this.field('text', 'preheader', 'Preview Text', s.preheader || '');
            html += '</div>';
            return html;
        },

        /* ── Block settings HTML ── */
        renderBlockSettings: function (block) {
            var type = block.type;
            var p = block.props || {};
            var label = BLOCK_DEFS[type] ? BLOCK_DEFS[type].label : type;
            var html = '<div class="ams-etb-settings-group"><h4>' + label + ' Settings</h4>';

            switch (type) {
                case 'text':
                    html += this.field('textarea', 'content', 'Content (HTML)', p.content || '');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    html += this.alignField('align', p.align || 'left');
                    break;
                case 'image':
                    html += this.field('text', 'src', 'Image URL', p.src || '');
                    html += this.field('text', 'alt', 'Alt Text', p.alt || '');
                    html += this.field('text', 'width', 'Width', p.width || '100%');
                    html += this.field('text', 'link', 'Link URL', p.link || '');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    html += this.alignField('align', p.align || 'center');
                    break;
                case 'button':
                    html += this.field('text', 'text', 'Button Text', p.text || 'Click Here');
                    html += this.field('text', 'url', 'URL', p.url || '#');
                    html += this.field('text', 'bgColor', 'Background', p.bgColor || '#2271b1');
                    html += this.field('text', 'textColor', 'Text Color', p.textColor || '#ffffff');
                    html += this.field('text', 'borderRadius', 'Radius', p.borderRadius || '4px');
                    html += this.field('text', 'padding', 'Button Padding', p.padding || '12px 24px');
                    html += this.field('text', 'containerPadding', 'Container Padding', p.containerPadding || '10px 20px');
                    html += this.alignField('align', p.align || 'center');
                    break;
                case 'divider':
                    html += this.field('text', 'color', 'Color', p.color || '#ccc');
                    html += this.field('text', 'thickness', 'Thickness', p.thickness || '1px');
                    html += this.field('select', 'style', 'Style', p.style || 'solid', { solid: 'Solid', dashed: 'Dashed', dotted: 'Dotted' });
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'spacer':
                    html += this.field('text', 'height', 'Height', p.height || '20px');
                    break;
                case 'product-card':
                    html += this.field('text', 'productName', 'Product Name', p.productName || '');
                    html += this.field('text', 'productUrl', 'Product URL', p.productUrl || '');
                    html += this.field('text', 'imageUrl', 'Image URL', p.imageUrl || '');
                    html += this.field('text', 'price', 'Price', p.price || '');
                    html += this.field('text', 'buttonText', 'Button Text', p.buttonText || 'Shop Now');
                    html += this.field('text', 'buttonColor', 'Button Color', p.buttonColor || '#2271b1');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'reviews':
                    html += this.field('select', 'mode', 'Mode', p.mode || 'review_request', { review_request: 'Review Request CTA', social_proof: 'Social Proof Cards', review_gate: 'Star Rating Gate' });
                    html += this.field('text', 'heading', 'Heading', p.heading || '');
                    html += this.field('text', 'buttonText', 'Button Text', p.buttonText || '');
                    html += this.field('text', 'buttonColor', 'Button Color', p.buttonColor || '#2271b1');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    break;
                case 'social-links':
                    html += this.field('text', 'facebook', 'Facebook', p.facebook || '');
                    html += this.field('text', 'instagram', 'Instagram', p.instagram || '');
                    html += this.field('text', 'twitter', 'X/Twitter', p.twitter || '');
                    html += this.field('text', 'youtube', 'YouTube', p.youtube || '');
                    html += this.field('text', 'padding', 'Padding', p.padding || '10px 20px');
                    html += this.alignField('align', p.align || 'center');
                    break;
                case 'unsubscribe-footer':
                    html += this.field('textarea', 'text', 'Footer Text', p.text || '');
                    html += this.field('text', 'linkText', 'Link Text', p.linkText || 'Unsubscribe');
                    html += this.field('text', 'padding', 'Padding', p.padding || '20px');
                    html += this.alignField('align', p.align || 'center');
                    break;
                case 'blank-row':
                    html += this.field('text', 'width', 'Width', p.width || '100%');
                    html += this.field('text', 'height', 'Height', p.height || '40px');
                    html += this.field('text', 'bgColor', 'Background', p.bgColor || '#f7f7f7');
                    break;
                default:
                    html += '<p>No settings for this block.</p>';
            }
            html += '</div>';
            return html;
        },

        /* Field helpers */
        field: function (type, name, label, value, options) {
            var html = '<div class="ams-etb-field"><label>' + this.esc(label) + '</label>';
            if (type === 'select') {
                html += '<select class="ams-etb-input" data-prop="' + name + '">';
                for (var k in options) {
                    html += '<option value="' + this.esc(k) + '"' + (k == value ? ' selected' : '') + '>' + this.esc(options[k]) + '</option>';
                }
                html += '</select>';
            } else if (type === 'textarea') {
                html += '<textarea class="ams-etb-input" data-prop="' + name + '" rows="5">' + this.esc(value || '') + '</textarea>';
            } else {
                html += '<input type="' + type + '" class="ams-etb-input" data-prop="' + name + '" value="' + this.esc(value || '') + '" />';
            }
            html += '</div>';
            return html;
        },

        alignField: function (name, value) {
            var html = '<div class="ams-etb-field"><label>Alignment</label><div class="ams-etb-align-group">';
            var aligns = ['left', 'center', 'right'];
            var icons = { left: 'dashicons-editor-alignleft', center: 'dashicons-editor-aligncenter', right: 'dashicons-editor-alignright' };
            for (var i = 0; i < aligns.length; i++) {
                html += '<button class="ams-etb-align-btn' + (value === aligns[i] ? ' active' : '') + '" data-prop="' + name + '" data-value="' + aligns[i] + '"><span class="dashicons ' + icons[aligns[i]] + '"></span></button>';
            }
            html += '</div></div>';
            return html;
        },

        esc: function (str) {
            if (!str) return '';
            return String(str).replace(/&/g, '&amp;').replace(/</g, '&lt;').replace(/>/g, '&gt;').replace(/"/g, '&quot;');
        },

        /* ── Event binding ── */
        bindEvents: function () {
            var self = this;

            /* Tab switching */
            this.el.on('click', '.ams-etb-tab', function () {
                var panel = $(this).data('panel');
                self.el.find('.ams-etb-tab').removeClass('active');
                $(this).addClass('active');
                self.el.find('.ams-etb-panel').removeClass('active');
                self.el.find('.ams-etb-panel[data-panel="' + panel + '"]').addClass('active');
            });

            /* ── Drag from palette ── */
            this.el.on('dragstart', '.ams-etb-block-item', function (e) {
                e.originalEvent.dataTransfer.setData('block-type', $(this).data('type'));
                e.originalEvent.dataTransfer.effectAllowed = 'copy';
                $(this).addClass('dragging');
                self._dragging = true;
            });

            this.el.on('dragend', '.ams-etb-block-item', function () {
                $(this).removeClass('dragging');
                setTimeout(function () { self._dragging = false; }, 50);
            });

            /* ── Drop zones ── */
            this.el.on('dragover', '.ams-etb-drop-zone, .ams-etb-row', function (e) {
                e.preventDefault();
                e.originalEvent.dataTransfer.dropEffect = 'copy';
                $(this).addClass('drag-over');
            }).on('dragleave', '.ams-etb-drop-zone, .ams-etb-row', function () {
                $(this).removeClass('drag-over');
            }).on('drop', '.ams-etb-drop-zone, .ams-etb-row', function (e) {
                e.preventDefault();
                e.stopPropagation();
                $(this).removeClass('drag-over');
                var type = e.originalEvent.dataTransfer.getData('block-type');
                if (!type) return;
                var defaults = BLOCK_DEFS[type] ? $.extend(true, {}, BLOCK_DEFS[type].defaults) : {};
                var rowIndex = $(this).data('index');
                if (typeof rowIndex !== 'undefined') {
                    self.structure.rows.splice(rowIndex + 1, 0, { blocks: [{ type: type, props: defaults }] });
                } else {
                    self.structure.rows.push({ blocks: [{ type: type, props: defaults }] });
                }
                self.refreshCanvas();
                var newIdx = (typeof rowIndex !== 'undefined') ? rowIndex + 1 : self.structure.rows.length - 1;
                self.selectBlock(newIdx, 0);
            });

            /* Click palette item (fallback for non-drag) */
            this.el.on('click', '.ams-etb-block-item', function () {
                if (self._dragging) return;
                var type = $(this).data('type');
                if (!type) return;
                var defaults = BLOCK_DEFS[type] ? $.extend(true, {}, BLOCK_DEFS[type].defaults) : {};
                self.structure.rows.push({ blocks: [{ type: type, props: defaults }] });
                self.refreshCanvas();
                self.selectBlock(self.structure.rows.length - 1, 0);
            });

            /* Row actions */
            this.el.on('click', '.ams-etb-row-action.delete', function (e) {
                e.stopPropagation();
                var idx = $(this).closest('.ams-etb-row').data('index');
                self.structure.rows.splice(idx, 1);
                self.selectedRow = null;
                self.refreshCanvas();
            });

            this.el.on('click', '.ams-etb-row-action.duplicate', function (e) {
                e.stopPropagation();
                var idx = $(this).closest('.ams-etb-row').data('index');
                var clone = JSON.parse(JSON.stringify(self.structure.rows[idx]));
                self.structure.rows.splice(idx + 1, 0, clone);
                self.refreshCanvas();
            });

            /* Select block */
            this.el.on('click', '.ams-etb-block', function (e) {
                e.stopPropagation();
                self.selectBlock($(this).data('row'), $(this).data('block'));
            });

            this.el.on('click', '.ams-etb-row', function () {
                var rowIdx = $(this).data('index');
                var blocks = self.structure.rows[rowIdx] ? self.structure.rows[rowIdx].blocks : [];
                if (blocks.length === 1) self.selectBlock(rowIdx, 0);
            });

            /* Settings changes */
            this.el.on('change input', '.ams-etb-input', function () {
                var prop = $(this).data('prop');
                var val = $(this).is(':checkbox') ? $(this).is(':checked') : $(this).val();
                var panel = $(this).closest('.ams-etb-panel').data('panel');

                if (panel === 'settings') {
                    self.structure.settings[prop] = val;
                    self.refreshCanvas();
                } else if (panel === 'block-settings' && self.selectedRow !== null) {
                    var block = self.structure.rows[self.selectedRow].blocks[0];
                    block.props[prop] = val;
                    self.refreshCanvas();
                }
            });

            /* Alignment buttons */
            this.el.on('click', '.ams-etb-align-btn', function () {
                var prop = $(this).data('prop');
                var val = $(this).data('value');
                $(this).siblings().removeClass('active');
                $(this).addClass('active');
                if (self.selectedRow !== null) {
                    self.structure.rows[self.selectedRow].blocks[0].props[prop] = val;
                    self.refreshCanvas();
                }
            });

            /* Browse templates */
            this.el.on('click', '.ams-etb-browse-templates', function () {
                self.showTemplateChooser();
            });

            /* Preview */
            this.el.on('click', '.ams-etb-preview-btn', function () {
                var html = self.generateFullHtml();
                apiFetch({
                    path: '/ams/v1/admin/campaigns/preview',
                    method: 'POST',
                    headers: { 'X-WP-Nonce': cfg.nonce },
                    data: { body_html: html },
                }).then(function (res) {
                    var w = window.open('', 'email_preview', 'width=700,height=600');
                    w.document.open();
                    w.document.write(res.html || html);
                    w.document.close();
                });
            });

            /* Save */
            this.el.on('click', '.ams-etb-save-btn', function () {
                if (!self.campaignId) return;
                var btn = $(this);
                btn.prop('disabled', true).text('Saving...');

                var html = self.generateFullHtml();
                var text = self.generatePlainText();

                apiFetch({
                    path: '/ams/v1/admin/campaigns/' + self.campaignId,
                    method: 'PUT',
                    headers: { 'X-WP-Nonce': cfg.nonce },
                    data: {
                        body_html: html,
                        body_text: text,
                        _blocks_json: JSON.stringify(self.structure),
                    },
                }).then(function () {
                    btn.prop('disabled', false).text('Save');
                    self.showNotice('Saved!', 'success');
                }).catch(function (err) {
                    btn.prop('disabled', false).text('Save');
                    self.showNotice('Error: ' + (err.message || 'Save failed.'), 'error');
                });
            });
        },

        /* ── Select block + open settings ── */
        selectBlock: function (rowIdx, blockIdx) {
            if (!this.structure.rows[rowIdx] || !this.structure.rows[rowIdx].blocks[blockIdx]) return;
            this.selectedRow = rowIdx;
            this.el.find('.ams-etb-row').removeClass('selected');
            this.el.find('.ams-etb-block').removeClass('selected');
            var $row = this.el.find('.ams-etb-row[data-index="' + rowIdx + '"]');
            $row.addClass('selected');
            $row.find('.ams-etb-block[data-block="' + blockIdx + '"]').addClass('selected');

            var block = this.structure.rows[rowIdx].blocks[blockIdx];
            this.el.find('.ams-etb-panel[data-panel="block-settings"]').html(this.renderBlockSettings(block));
            this.el.find('.ams-etb-tab').removeClass('active');
            this.el.find('.ams-etb-tab[data-panel="block-settings"]').addClass('active');
            this.el.find('.ams-etb-panel').removeClass('active');
            this.el.find('.ams-etb-panel[data-panel="block-settings"]').addClass('active');
        },

        /* ── Refresh canvas ── */
        refreshCanvas: function () {
            var s = this.structure.settings;
            var body = this.el.find('.ams-etb-email-body');
            body.html(this.renderRows());
            body.css('background', s.contentBg || '#fff');
            this.el.find('.ams-etb-email-frame').css('max-width', (parseInt(s.maxWidth) || 600) + 'px');
            this.initSortable();

            if (this.selectedRow !== null && this.structure.rows[this.selectedRow]) {
                var $row = this.el.find('.ams-etb-row[data-index="' + this.selectedRow + '"]');
                $row.addClass('selected');
                $row.find('.ams-etb-block').first().addClass('selected');
            }
        },

        /* ── jQuery UI Sortable for row reordering ── */
        initSortable: function () {
            var self = this;
            this.el.find('.ams-etb-drop-zone.has-blocks').sortable({
                items: '.ams-etb-row',
                handle: '.ams-etb-row-action.move',
                placeholder: 'ams-sortable-placeholder',
                tolerance: 'pointer',
                update: function () {
                    var newOrder = [];
                    $(this).find('.ams-etb-row').each(function () {
                        var idx = $(this).data('index');
                        newOrder.push(self.structure.rows[idx]);
                    });
                    self.structure.rows = newOrder;
                    self.refreshCanvas();
                }
            });
        },

        showNotice: function (message, type) {
            var notice = $('<div class="notice notice-' + type + ' is-dismissible" style="position:fixed;top:40px;right:20px;z-index:9999;padding:10px 15px;"><p>' + message + '</p></div>');
            $('body').append(notice);
            setTimeout(function () { notice.fadeOut(400, function () { $(this).remove(); }); }, 3000);
        },

        /* ── Generate full email HTML for sending ── */
        generateFullHtml: function () {
            var s = this.structure.settings;
            var font = FONT_STACK;
            var bgColor = s.bgColor || '#f4f4f4';
            var contentBg = s.contentBg || '#ffffff';
            var maxWidth = s.maxWidth || '600';
            var preheader = s.preheader || '';
            var textColor = s.textColor || '#333333';
            var linkColor = s.linkColor || '#2271b1';
            var fontSize = s.fontSize || '16px';

            var bodyContent = '';
            for (var i = 0; i < this.structure.rows.length; i++) {
                var row = this.structure.rows[i];
                for (var j = 0; j < row.blocks.length; j++) {
                    var block = row.blocks[j];
                    bodyContent += '<tr><td>' + this.generateBlockHtml(block, s) + '</td></tr>';
                }
            }

            return '<!DOCTYPE html>\n' +
                '<html lang="en" xmlns="http://www.w3.org/1999/xhtml" xmlns:v="urn:schemas-microsoft-com:vml" xmlns:o="urn:schemas-microsoft-com:office:office">\n' +
                '<head>\n<meta charset="utf-8">\n<meta name="viewport" content="width=device-width, initial-scale=1.0">\n' +
                '<meta http-equiv="X-UA-Compatible" content="IE=edge">\n' +
                '<!--[if mso]><xml><o:OfficeDocumentSettings><o:AllowPNG/><o:PixelsPerInch>96</o:PixelsPerInch></o:OfficeDocumentSettings></xml><![endif]-->\n' +
                '<style>\n' + FONT_IMPORT + '\n' +
                '@media only screen and (max-width:' + maxWidth + 'px) {\n' +
                '  .ams-container { width:100% !important; }\n  img { max-width:100% !important; height:auto !important; }\n}\n' +
                '</style>\n</head>\n' +
                '<body style="margin:0;padding:0;background-color:' + bgColor + ';font-family:' + font + ';">\n' +
                (preheader ? '<div style="display:none;font-size:1px;color:' + bgColor + ';line-height:1px;max-height:0px;max-width:0px;opacity:0;overflow:hidden;">' + preheader + '</div>\n' : '') +
                '<!--[if mso]><table role="presentation" cellpadding="0" cellspacing="0" border="0" width="' + maxWidth + '" align="center"><tr><td><![endif]-->\n' +
                '<table class="ams-container" role="presentation" cellpadding="0" cellspacing="0" border="0" width="' + maxWidth + '" align="center" style="max-width:' + maxWidth + 'px;margin:0 auto;background-color:' + contentBg + ';">\n' +
                bodyContent + '\n</table>\n' +
                '<!--[if mso]></td></tr></table><![endif]-->\n</body>\n</html>';
        },

        generateBlockHtml: function (block, s) {
            var type = block.type;
            var p = block.props || {};
            var font = FONT_STACK;
            var textColor = s.textColor || '#333333';
            var linkColor = s.linkColor || '#2271b1';
            var pad = p.padding || '10px 20px';

            switch (type) {
                case 'text':
                    return '<div style="padding:' + pad + ';text-align:' + (p.align || 'left') + ';font-family:' + font + ';color:' + textColor + ';font-size:' + (s.fontSize || '16px') + ';line-height:1.6;">' + (p.content || '') + '</div>';
                case 'image':
                    var img = '<img src="' + (p.src || '') + '" alt="' + (p.alt || '') + '" style="max-width:' + (p.width || '100%') + ';height:auto;display:block;margin:0 auto;" />';
                    if (p.link) img = '<a href="' + p.link + '" target="_blank">' + img + '</a>';
                    return '<div style="padding:' + pad + ';text-align:' + (p.align || 'center') + ';">' + img + '</div>';
                case 'button':
                    return '<div style="padding:' + (p.containerPadding || '10px 20px') + ';text-align:' + (p.align || 'center') + ';"><a href="' + (p.url || '#') + '" target="_blank" style="display:inline-block;background:' + (p.bgColor || '#2271b1') + ';color:' + (p.textColor || '#fff') + ';font-family:' + font + ';font-size:16px;font-weight:600;text-decoration:none;padding:' + (p.padding || '12px 24px') + ';border-radius:' + (p.borderRadius || '4px') + ';">' +
                        '<!--[if mso]><i style="letter-spacing:24px;mso-font-width:-100%;mso-text-raise:18pt;">&nbsp;</i><![endif]--><span style="mso-text-raise:9pt;">' + (p.text || 'Click') + '</span><!--[if mso]><i style="letter-spacing:24px;mso-font-width:-100%;">&nbsp;</i><![endif]-->' +
                        '</a></div>';
                case 'divider':
                    return '<div style="padding:' + pad + ';"><hr style="border:0;border-top:' + (p.thickness || '1px') + ' ' + (p.style || 'solid') + ' ' + (p.color || '#ccc') + ';margin:0;" /></div>';
                case 'spacer':
                    return '<div style="height:' + (p.height || '20px') + ';line-height:' + (p.height || '20px') + ';">&nbsp;</div>';
                case 'blank-row':
                    return '<div style="width:' + (p.width || '100%') + ';height:' + (p.height || '40px') + ';background:' + (p.bgColor || '#f7f7f7') + ';">&nbsp;</div>';
                case 'product-card':
                    return '<table cellpadding="0" cellspacing="0" border="0" width="100%" style="font-family:' + font + ';"><tr>' +
                        '<td style="width:40%;padding:10px;"><img src="' + (p.imageUrl || '') + '" alt="' + (p.productName || '') + '" style="max-width:100%;height:auto;" /></td>' +
                        '<td style="width:60%;padding:10px;vertical-align:top;">' +
                        '<h3 style="margin:0 0 8px;font-family:' + font + ';color:' + textColor + ';">' + (p.productName || 'Product') + '</h3>' +
                        '<p style="margin:0 0 12px;font-family:' + font + ';color:' + textColor + ';font-size:18px;font-weight:600;">' + (p.price || '') + '</p>' +
                        '<a href="' + (p.productUrl || '#') + '" target="_blank" style="display:inline-block;background:' + (p.buttonColor || '#2271b1') + ';color:#fff;font-family:' + font + ';font-size:14px;font-weight:600;text-decoration:none;padding:10px 20px;border-radius:4px;">' + (p.buttonText || 'Shop Now') + '</a>' +
                        '</td></tr></table>';
                case 'reviews':
                    var rh = '<div style="text-align:center;padding:20px;font-family:' + font + ';background:#f9f9f9;border-radius:8px;">';
                    rh += '<h3 style="margin:0 0 12px;font-family:' + font + ';color:' + textColor + ';">' + (p.heading || 'Reviews') + '</h3>';
                    if (p.mode === 'review_request') {
                        rh += '<p style="font-family:' + font + ';color:#666;margin:0 0 16px;">We\u2019d love your feedback.</p>';
                        rh += '<a href="#" style="display:inline-block;background:' + (p.buttonColor || '#2271b1') + ';color:#fff;font-family:' + font + ';font-size:14px;font-weight:600;text-decoration:none;padding:12px 24px;border-radius:4px;">' + (p.buttonText || 'Leave a Review') + '</a>';
                    } else if (p.mode === 'social_proof') {
                        rh += '<div style="background:#fff;border:1px solid #e0e0e0;border-radius:6px;padding:16px;text-align:left;">';
                        rh += '<div style="color:#f5a623;font-size:18px;">\u2605\u2605\u2605\u2605\u2605</div>';
                        rh += '<p style="font-family:' + font + ';color:' + textColor + ';margin:4px 0 0;font-style:italic;">"Amazing product!"</p></div>';
                    } else if (p.mode === 'review_gate') {
                        rh += '<p style="font-family:' + font + ';color:#666;margin:0 0 12px;">How would you rate your experience?</p>';
                        rh += '<div style="font-size:32px;letter-spacing:8px;color:#f5a623;">\u2605\u2605\u2605\u2605\u2605</div>';
                    }
                    rh += '</div>';
                    return rh;
                case 'social-links':
                    var links = '<div style="text-align:' + (p.align || 'center') + ';padding:' + pad + ';">';
                    if (p.facebook) links += '<a href="' + p.facebook + '" target="_blank" style="display:inline-block;margin:0 8px;color:' + linkColor + ';text-decoration:none;font-family:' + font + ';">Facebook</a>';
                    if (p.instagram) links += '<a href="' + p.instagram + '" target="_blank" style="display:inline-block;margin:0 8px;color:' + linkColor + ';text-decoration:none;font-family:' + font + ';">Instagram</a>';
                    if (p.twitter) links += '<a href="' + p.twitter + '" target="_blank" style="display:inline-block;margin:0 8px;color:' + linkColor + ';text-decoration:none;font-family:' + font + ';">X</a>';
                    if (p.youtube) links += '<a href="' + p.youtube + '" target="_blank" style="display:inline-block;margin:0 8px;color:' + linkColor + ';text-decoration:none;font-family:' + font + ';">YouTube</a>';
                    links += '</div>';
                    return links;
                case 'unsubscribe-footer':
                    return '<div style="text-align:' + (p.align || 'center') + ';padding:' + (p.padding || '20px') + ';font-family:' + font + ';font-size:12px;color:#999;">' +
                        '<p style="margin:0 0 8px;">' + (p.text || '') + '</p>' +
                        '<a href="{{unsubscribe_url}}" style="color:' + linkColor + ';text-decoration:underline;">' + (p.linkText || 'Unsubscribe') + '</a></div>';
                default:
                    return '';
            }
        },

        generatePlainText: function () {
            var text = '';
            for (var i = 0; i < this.structure.rows.length; i++) {
                var row = this.structure.rows[i];
                for (var j = 0; j < row.blocks.length; j++) {
                    var block = row.blocks[j];
                    var p = block.props || {};
                    switch (block.type) {
                        case 'text':
                            var t = (p.content || '').replace(/<br\s*\/?>/gi, '\n').replace(/<\/p>/gi, '\n').replace(/<[^>]+>/g, '');
                            text += t + '\n\n'; break;
                        case 'button': text += (p.text || '') + ': ' + (p.url || '') + '\n\n'; break;
                        case 'divider': text += '---\n\n'; break;
                        case 'product-card': text += (p.productName || '') + ' - ' + (p.price || '') + '\n' + (p.productUrl || '') + '\n\n'; break;
                        case 'reviews': text += (p.heading || '') + '\n\n'; break;
                        case 'social-links':
                            if (p.facebook) text += 'Facebook: ' + p.facebook + '\n';
                            if (p.instagram) text += 'Instagram: ' + p.instagram + '\n';
                            if (p.twitter) text += 'X: ' + p.twitter + '\n';
                            text += '\n'; break;
                        case 'unsubscribe-footer': text += (p.text || '') + '\n{{unsubscribe_url}}\n\n'; break;
                    }
                }
            }
            return text.trim();
        }
    }; /* end Editor */

    /* ── Campaign List (React) ── */
    function CampaignsList() {
        var _s = useState([]), campaigns = _s[0], setCampaigns = _s[1];
        var _l = useState(true), loading = _l[0], setLoading = _l[1];

        function load() {
            setLoading(true);
            apiFetch({ path: '/ams/v1/admin/campaigns', headers: { 'X-WP-Nonce': cfg.nonce } })
                .then(function (d) { setCampaigns(d); setLoading(false); })
                .catch(function () { setLoading(false); });
        }
        useEffect(load, []);

        function del(id) {
            if (!confirm('Delete this campaign?')) return;
            apiFetch({ path: '/ams/v1/admin/campaigns/' + id, method: 'DELETE', headers: { 'X-WP-Nonce': cfg.nonce } }).then(load);
        }

        var colors = { draft: '#dba617', scheduled: '#2271b1', sent: '#00a32a', cancelled: '#cc1818' };
        if (loading) return el(Spinner);
        if (!campaigns.length) return el('p', {}, 'No campaigns yet. Click "Create Campaign" to get started.');

        return el('table', { className: 'widefat striped' },
            el('thead', {}, el('tr', {}, el('th', {}, 'Name'), el('th', {}, 'Type'), el('th', {}, 'Segment'), el('th', {}, 'Status'), el('th', {}, 'Scheduled'), el('th', {}, 'Actions'))),
            el('tbody', {}, campaigns.map(function (c) {
                return el('tr', { key: c.id },
                    el('td', {}, el('a', { href: cfg.listUrl + '&view=editor&campaign_id=' + c.id, style: { fontWeight: 600 } }, c.name || '(Untitled)')),
                    el('td', {}, (c.type || 'email').toUpperCase()),
                    el('td', {}, c.segment_name || '\u2014'),
                    el('td', {}, el('span', { style: { color: colors[c.status] || '#333', fontWeight: 600 } }, (c.status || 'draft').toUpperCase())),
                    el('td', {}, c.scheduled_at || '\u2014'),
                    el('td', {}, el(Button, { isDestructive: true, isSmall: true, variant: 'secondary', onClick: function () { del(c.id); } }, 'Delete'))
                );
            }))
        );
    }

    /* ── Campaign Create (React) ── */
    function CampaignCreate() {
        var _n = useState(''), name = _n[0], setName = _n[1];
        var _t = useState('email'), type = _t[0], setType = _t[1];
        var _seg = useState(''), segmentId = _seg[0], setSegmentId = _seg[1];
        var _subj = useState(''), subject = _subj[0], setSubject = _subj[1];
        var _segments = useState([]), segments = _segments[0], setSegments = _segments[1];
        var _saving = useState(false), saving = _saving[0], setSaving = _saving[1];
        var _msg = useState(''), message = _msg[0], setMessage = _msg[1];

        useEffect(function () {
            apiFetch({ path: '/ams/v1/admin/campaigns/segments', headers: { 'X-WP-Nonce': cfg.nonce } }).then(setSegments).catch(function () {});
        }, []);

        function create() {
            if (!name.trim()) { setMessage('Name is required.'); return; }
            setSaving(true);
            apiFetch({
                path: '/ams/v1/admin/campaigns', method: 'POST', headers: { 'X-WP-Nonce': cfg.nonce },
                data: { name: name, type: type, segment_id: segmentId ? parseInt(segmentId, 10) : 0, subject: subject },
            }).then(function (res) {
                window.location.href = cfg.listUrl + '&view=editor&campaign_id=' + res.id;
            }).catch(function (err) { setSaving(false); setMessage('Error: ' + (err.message || 'Create failed.')); });
        }

        var segOpts = [{ value: '', label: '\u2014 All Subscribers \u2014' }];
        segments.forEach(function (s) { segOpts.push({ value: String(s.id), label: s.name + ' (' + s.subscriber_count + ')' }); });

        return el('div', { style: { maxWidth: '500px' } },
            message ? el(Notice, { status: 'error', isDismissible: true, onDismiss: function () { setMessage(''); } }, message) : null,
            el(TextControl, { label: 'Campaign Name', value: name, onChange: setName, __nextHasNoMarginBottom: true }),
            el(SelectControl, { label: 'Type', value: type, options: [{ value: 'email', label: 'Email' }, { value: 'sms', label: 'SMS' }], onChange: setType, __nextHasNoMarginBottom: true }),
            el(SelectControl, { label: 'Segment', value: segmentId, options: segOpts, onChange: setSegmentId, __nextHasNoMarginBottom: true }),
            type === 'email' ? el(TextControl, { label: 'Subject Line', value: subject, onChange: setSubject, __nextHasNoMarginBottom: true }) : null,
            el('div', { style: { marginTop: '16px' } }, el(Button, { isPrimary: true, isBusy: saving, onClick: create, variant: 'primary' }, 'Create & Open Editor'))
        );
    }

    /* ── Mount points ── */
    function mount(id, component) {
        var node = document.getElementById(id);
        if (node) wp.element.render(el(component), node);
    }

    $(document).ready(function () {
        mount('ams-campaigns-list', CampaignsList);
        mount('ams-campaign-create', CampaignCreate);

        /* Mount jQuery-based editor */
        var editorNode = document.getElementById('ams-email-editor');
        if (editorNode) {
            Editor.init(editorNode);
        }
    });

})(jQuery);
